#include <cuda_runtime.h>

#include <cstdio>
#include <cstdlib>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>
#include <vector>

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

#define CUDA_CHECK(call)                                                      \
  do {                                                                        \
    cudaError_t err__ = (call);                                               \
    if (err__ != cudaSuccess) {                                               \
      std::fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__,   \
                   cudaGetErrorString(err__));                                \
      std::exit(EXIT_FAILURE);                                                \
    }                                                                         \
  } while (0)

void initialize_data(float* f) {
  const float two_pi = 2.0f * 3.14159265358979323846f;

  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N - 1) {
        f[IDX(i, j)] = sinf(j * two_pi / (N - 1));
      } else if (j == 0 || j == N - 1) {
        f[IDX(i, j)] = sinf(i * two_pi / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

__global__ void jacobi_kernel(const float* f_old, float* f, float* partial) {
  __shared__ float sdata[256];

  const int tx = threadIdx.x;
  const int ty = threadIdx.y;
  const int tid = ty * blockDim.x + tx;

  const int i = blockIdx.x * blockDim.x + tx + 1;
  const int j = blockIdx.y * blockDim.y + ty + 1;

  float local = 0.0f;

  if (i <= N - 2 && j <= N - 2) {
    const int c = IDX(i, j);
    const float t = 0.25f * (f_old[IDX(i - 1, j)] +
                             f_old[IDX(i + 1, j)] +
                             f_old[IDX(i, j - 1)] +
                             f_old[IDX(i, j + 1)]);
    const float df = t - f_old[c];
    f[c] = t;
    local = df * df;
  }

  sdata[tid] = local;
  __syncthreads();

  for (int s = 128; s > 0; s >>= 1) {
    if (tid < s) {
      sdata[tid] += sdata[tid + s];
    }
    __syncthreads();
  }

  if (tid == 0) {
    partial[blockIdx.y * gridDim.x + blockIdx.x] = sdata[0];
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  const size_t num_elems = static_cast<size_t>(N) * static_cast<size_t>(N);
  const size_t bytes = num_elems * sizeof(float);

  float* f = (float*)std::malloc(bytes);
  float* f_old = (float*)std::malloc(bytes);

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  initialize_data(f);
  initialize_data(f_old);

  float* d_f = nullptr;
  float* d_f_old = nullptr;

  CUDA_CHECK(cudaMalloc(&d_f, bytes));
  CUDA_CHECK(cudaMalloc(&d_f_old, bytes));

  CUDA_CHECK(cudaMemcpy(d_f, f, bytes, cudaMemcpyHostToDevice));
  CUDA_CHECK(cudaMemcpy(d_f_old, f_old, bytes, cudaMemcpyHostToDevice));

  const dim3 block(16, 16);
  const dim3 grid((N - 2 + block.x - 1) / block.x,
                  (N - 2 + block.y - 1) / block.y);
  const int num_blocks = static_cast<int>(grid.x * grid.y);

  float* d_partial = nullptr;
  CUDA_CHECK(cudaMalloc(&d_partial, static_cast<size_t>(num_blocks) * sizeof(float)));

  std::vector<float> h_partial(num_blocks);

  const int max_iters = 10000;
  int num_iters = 0;

  auto start = std::chrono::steady_clock::now();

  while (error > tolerance && num_iters < max_iters) {
    error = 0.0f;

    jacobi_kernel<<<grid, block>>>(d_f_old, d_f, d_partial);
    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaMemcpy(h_partial.data(), d_partial,
                          static_cast<size_t>(num_blocks) * sizeof(float),
                          cudaMemcpyDeviceToHost));

    for (int b = 0; b < num_blocks; ++b) {
      error += h_partial[b];
    }

    float* tmp = d_f_old;
    d_f_old = d_f;
    d_f = tmp;

    error = sqrtf(error / (N * N));

    if (num_iters % 1000 == 0) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    ++num_iters;
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (error <= tolerance && num_iters < max_iters) {
    std::cout << "PASS" << std::endl;
  } else {
    std::cout << "FAIL" << std::endl;
    cudaFree(d_partial);
    cudaFree(d_f);
    cudaFree(d_f_old);
    std::free(f);
    std::free(f_old);
    return -1;
  }

  CUDA_CHECK(cudaFree(d_partial));
  CUDA_CHECK(cudaFree(d_f));
  CUDA_CHECK(cudaFree(d_f_old));

  std::free(f);
  std::free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
